1	/**
2	 * LayerInfinite MCP Server — prompts/agent-setup.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Mode-aware system prompt that configures the agent's relationship
5	 * with LayerInfinite's decision layer.
6	 * ══════════════════════════════════════════════════════════════
7	 */
8	
9	import type { LIConfig } from '../config.js';
10	
11	export const AGENT_SETUP_PROMPT_NAME = 'layerinfinite-setup';
12	
13	export const AGENT_SETUP_PROMPT_DESCRIPTION =
14	  'System configuration for LayerInfinite integration. ' +
15	  'Configures how the agent interacts with the LI decision layer.';
16	
17	export function getAgentSetupPrompt(config: LIConfig) {
18	  const mode = config.mode;
19	
20	  const base =
21	    'You are integrated with LayerInfinite (LI), an outcome-ranked decision ' +
22	    'intelligence layer. LI tracks the real-world success rates of every action ' +
23	    'you take and uses this data to help you make better decisions over time.\n\n' +
24	    'ALWAYS call li_log after executing any action to report the outcome. ' +
25	    'This is how LI learns — every logged outcome makes future recommendations more accurate.\n\n' +
26	    'CIRCUIT BREAKER: If you detect an action is consistently failing (e.g., 3+ ' +
27	    'consecutive failures with the same error), use li_toggle_action to disable it. ' +
28	    'This immediately removes it from all LI recommendations. The developer can ' +
29	    're-enable it from the dashboard after fixing the underlying issue.\n\n';
30	
31	  if (!mode) {
32	    return {
33	      messages: [{
34	        role: 'user' as const,
35	        content: {
36	          type: 'text' as const,
37	          text: base +
38	            'You are in BOOTSTRAP mode. LI is learning from your actions. ' +
39	            'Make your own decisions and log every outcome via li_log. ' +
40	            'Once enough data is collected, your developer can enable ' +
41	            'recommend, assist, or auto mode for intelligent action guidance.',
42	        },
43	      }],
44	    };
45	  }
46	
47	  if (mode === 'recommend') {
48	    return {
49	      messages: [{
50	        role: 'user' as const,
51	        content: {
52	          type: 'text' as const,
53	          text: base +
54	            'You are in RECOMMEND mode. Before deciding on an action, read the ' +
55	            'layerinfinite://tasks/{task} resource to see which actions perform best ' +
56	            'based on real production data. Use this data to inform your decision, ' +
57	            'but the final choice is yours. Log every outcome via li_log.',
58	        },
59	      }],
60	    };
61	  }
62	
63	  if (mode === 'assist') {
64	    return {
65	      messages: [{
66	        role: 'user' as const,
67	        content: {
68	          type: 'text' as const,
69	          text: base +
70	            'You are in ASSIST mode. Route all action execution through li_action. ' +
71	            'LI will check if a better-performing action exists and warn you with ' +
72	            'real evidence if your choice is suboptimal. You may proceed with your ' +
73	            'original choice or switch based on the data. Log every outcome via li_log.',
74	        },
75	      }],
76	    };
77	  }
78	
79	  // Auto mode
80	  return {
81	    messages: [{
82	      role: 'user' as const,
83	      content: {
84	        type: 'text' as const,
85	        text: base +
86	          'You are in AUTO mode. Route all action execution through li_action. ' +
87	          'LI will redirect to the statistically proven best action based on real ' +
88	          'production outcomes. Execute whatever action li_action returns — it may ' +
89	          'differ from your original intent. This is by design: LI has evidence from ' +
90	          'hundreds of real outcomes that you do not have. If the action fails, use ' +
91	          'li_fallback to get the next-best option. Log every outcome via li_log.',
92	      },
93	    }],
94	  };
95	}
