10	type BusinessOutcome = 'resolved' | 'partial' | 'failed' | 'unknown';
11	
12	interface CanonicalWebhookPayload {
13	    outcomeId: string;
14	    finalScore: number;
15	    businessOutcome: BusinessOutcome;
16	}
17	
18	function clamp01(value: number): number {
19	    if (value < 0) return 0;
20	    if (value > 1) return 1;
21	    return value;
22	}
23	
24	function getObject(value: unknown): Record<string, unknown> {
25	    if (value && typeof value === 'object' && !Array.isArray(value)) {
26	        return value as Record<string, unknown>;
27	    }
28	    return {};
29	}
30	
31	function extractStripePayload(payloadInput: unknown): CanonicalWebhookPayload | null {
32	    const payload = getObject(payloadInput);
33	    const eventData = getObject(payload.data);
34	    const eventObject = getObject(eventData.object);
35	    const objectPayload = Object.keys(eventObject).length > 0 ? eventObject : payload;
36	
37	    const metadata = getObject(objectPayload.metadata);
38	    const outcomeId = metadata.layerinfinite_outcome_id;
39	    const amountRefunded = Number(objectPayload.amount_refunded ?? 0);
40	    const amount = Number(objectPayload.amount ?? objectPayload.amount_received ?? 0);
41	    const eventType = String(payload.type ?? objectPayload.status ?? '').toLowerCase();
42	
43	    if (typeof outcomeId !== 'string') return null;
44	
45	    let finalScore = 0.5;
46	    let businessOutcome: BusinessOutcome = 'unknown';
47	
48	    if (Number.isFinite(amount) && amount > 0 && Number.isFinite(amountRefunded) && amountRefunded > 0) {
49	        finalScore = clamp01(amountRefunded / amount);
50	        businessOutcome = finalScore >= 1 ? 'resolved' : 'partial';
51	    } else if (
52	        eventType.includes('succeeded')
53	        || eventType.includes('completed')
54	        || eventType.includes('paid')
55	    ) {
56	        finalScore = 1.0;
57	        businessOutcome = 'resolved';
58	    } else if (
59	        eventType.includes('failed')
60	        || eventType.includes('canceled')
61	        || eventType.includes('expired')
62	    ) {
63	        finalScore = 0.0;
64	        businessOutcome = 'failed';
65	    }
66	
67	    return { outcomeId, finalScore, businessOutcome };
68	}
69	
70	function extractSendgridPayload(payloadInput: unknown): CanonicalWebhookPayload | null {
71	    const events = Array.isArray(payloadInput) ? payloadInput : [payloadInput];
72	
73	    for (const eventRow of events) {
74	        const eventPayload = getObject(eventRow);
75	        if (Object.keys(eventPayload).length === 0) continue;
76	
77	        const customArgs = getObject(eventPayload.custom_args);
78	        const uniqueArgs = getObject(eventPayload.unique_args);
79	        const outcomeId = customArgs.outcome_id ?? uniqueArgs.outcome_id;
80	        const event = String(eventPayload.event ?? '').toLowerCase();
81	
82	        if (typeof outcomeId !== 'string') {
83	            continue;
84	        }
85	
86	        if (event === 'delivered' || event === 'processed') {
87	            return { outcomeId, finalScore: 1.0, businessOutcome: 'resolved' };
88	        }
89	
90	        if (
91	            event === 'bounce'
92	            || event === 'blocked'
93	            || event === 'dropped'
94	            || event === 'deferred'
95	            || event === 'spamreport'
96	        ) {
97	            return { outcomeId, finalScore: 0.0, businessOutcome: 'failed' };
98	        }
99	
100	        return { outcomeId, finalScore: 0.5, businessOutcome: 'unknown' };
101	    }
102	
103	    return null;
104	}
105	
106	function extractGenericPayload(payloadInput: unknown): CanonicalWebhookPayload | null {
107	    const payload = getObject(payloadInput);
108	    const outcomeId = payload.outcome_id;
109	    const finalScore = Number(payload.final_score);
110	    const businessOutcome = String(payload.business_outcome) as BusinessOutcome;
111	
112	    const allowedOutcomes = ['resolved', 'partial', 'failed', 'unknown'];
113	    if (typeof outcomeId !== 'string') return null;
114	    if (Number.isNaN(finalScore)) return null;
115	    if (!allowedOutcomes.includes(businessOutcome)) return null;
116	
117	    return {
118	        outcomeId,
119	        finalScore: clamp01(finalScore),
120	        businessOutcome,
121	    };
122	}
123	
124	function extractPayload(provider: Provider, payloadInput: unknown): CanonicalWebhookPayload | null {
125	    if (provider === 'stripe') return extractStripePayload(payloadInput);
126	    if (provider === 'sendgrid') return extractSendgridPayload(payloadInput);
127	    return extractGenericPayload(payloadInput);
128	}
129	
130	function isWebhookAuthorized(params: {
131	    provider: Provider;
132	    c: Context;
133	    rawBody: string;
134	}): boolean {
135	    const sharedSecret = process.env.LI_WEBHOOK_SHARED_SECRET;
136	    const providedSharedSecret = params.c.req.header('x-layerinfinite-webhook-secret');
137	
138	    if (verifySharedSecret(sharedSecret, providedSharedSecret)) {
139	        return true;
140	    }
141	
142	    if (params.provider === 'stripe') {
143	        const stripeSigningSecret = process.env.STRIPE_WEBHOOK_SIGNING_SECRET;
144	        const stripeSignature = params.c.req.header('stripe-signature');
145	        const tolerance = Number(process.env.STRIPE_WEBHOOK_TOLERANCE_SECONDS ?? 300);
146	
147	        if (verifyStripeSignature(params.rawBody, stripeSignature, stripeSigningSecret, tolerance)) {
148	            return true;
149	        }
150	    }
151	
152	    if (params.provider === 'sendgrid') {
153	        const sendgridPublicKey = process.env.SENDGRID_EVENT_WEBHOOK_PUBLIC_KEY;
154	        const sendgridSignature = params.c.req.header('x-twilio-email-event-webhook-signature');
155	        const sendgridTimestamp = params.c.req.header('x-twilio-email-event-webhook-timestamp');
156	
157	        if (verifySendgridSignature(params.rawBody, sendgridTimestamp, sendgridSignature, sendgridPublicKey)) {
158	            return true;
159	        }
160	    }
161	
162	    // Keep local dev easy to test while keeping production strict.
163	    if (process.env.NODE_ENV !== 'production') {
164	        return true;
165	    }
166	
167	    return false;
168	}
169	
170	export default async function webhookRoute(c: Context): Promise<Response> {
171	    try {
172	        const provider = c.req.param('provider') as Provider;
173	        if (!['stripe', 'sendgrid', 'generic'].includes(provider)) {
174	            return c.json({ resolved: false }, 200);
175	        }
176	
177	        const rawBody = await c.req.text();
178	
179	        if (!isWebhookAuthorized({ provider, c, rawBody })) {
180	            return c.json({ resolved: false }, 401);
181	        }
182	
183	        let parsedPayload: unknown;
184	        try {
185	            parsedPayload = JSON.parse(rawBody);
186	        } catch {
187	            return c.json({ resolved: false }, 200);
188	        }
189	
190	        const payload = extractPayload(provider, parsedPayload);
191	
192	        if (!payload) {
193	            return c.json({ resolved: false }, 200);
194	        }
195	
196	        const { data: pending } = await supabase
197	            .from('dim_pending_signal_registrations')
198	            .select('registration_id, customer_id, resolved, event_type, platform')
199	            .eq('outcome_id', payload.outcomeId)
200	            .eq('platform', provider)
201	            .eq('resolved', false)
202	            .limit(1)
203	            .maybeSingle();
204	
205	        if (!pending) {
206	            return c.json({ resolved: false, outcome_id: payload.outcomeId }, 200);
207	        }
208	
209	        const { data: currentOutcome } = await supabase
210	            .from('fact_outcomes')
211	            .select('outcome_id, success')
212	            .eq('outcome_id', payload.outcomeId)
213	            .eq('customer_id', pending.customer_id)
214	            .limit(1)
215	            .maybeSingle();
216	
217	        if (!currentOutcome) {
218	            return c.json({ resolved: false, outcome_id: payload.outcomeId }, 200);
219	        }
220	
221	        const finalSignalSuccess = payload.finalScore >= 0.5;
222	        const crossEventStatus = currentOutcome.success === finalSignalSuccess
223	            ? 'confirmed'
224	            : 'conflict';
225	        const nowIso = new Date().toISOString();
226	
227	        const { error: outcomeUpdateError } = await supabase
228	            .from('fact_outcomes')
229	            .update({
230	                outcome_score: payload.finalScore,
231	                business_outcome: payload.businessOutcome,
232	                feedback_received_at: nowIso,
233	                signal_pending: false,
234	                signal_updated_at: nowIso,
235	                cross_event_status: crossEventStatus,
236	                cross_event_last_updated: nowIso,
237	                pending_registration_id: pending.registration_id,
238	            })
239	            .eq('outcome_id', payload.outcomeId)
240	            .eq('customer_id', pending.customer_id);
241	
242	        if (outcomeUpdateError) {
243	            return c.json({ resolved: false, outcome_id: payload.outcomeId }, 200);
244	        }
245	
246	        await supabase
247	            .from('dim_pending_signal_registrations')
248	            .update({
249	                resolved: true,
250	                resolved_at: nowIso,
251	                resolved_by: `${provider}_webhook`,
252	            })
253	            .eq('registration_id', pending.registration_id)
254	            .eq('customer_id', pending.customer_id);
255	
256	        if (crossEventStatus === 'conflict') {
257	            const { data: existingConflict } = await supabase
258	                .from('dim_discrepancy_log')
259	                .select('discrepancy_id')
260	                .eq('customer_id', pending.customer_id)
261	                .eq('outcome_id', payload.outcomeId)
262	                .eq('discrepancy_type', 'cross_event_conflict')
263	                .eq('resolved', false)
264	                .limit(1);
265	
266	            if (!existingConflict || existingConflict.length === 0) {
267	                await supabase
268	                    .from('dim_discrepancy_log')
269	                    .insert({
270	                        customer_id: pending.customer_id,
271	                        outcome_id: payload.outcomeId,
272	                        registration_id: pending.registration_id,
273	                        action_name: `${pending.platform}:${pending.event_type}`,
274	                        discrepancy_type: 'cross_event_conflict',
275	                        expected_outcome: currentOutcome.success,
276	                        actual_outcome: finalSignalSuccess,
277	                        signal_confidence: payload.finalScore,
278	                        detail:
279	                            `Webhook ${provider} contradicted initial outcome polarity. ` +
280	                            `initial_success=${String(currentOutcome.success)} final_score=${payload.finalScore.toFixed(4)}.`,
281	                    });
282	            }
283	        }
284	
285	        return c.json({
286	            resolved: true,
287	            outcome_id: payload.outcomeId,
288	            cross_event_status: crossEventStatus,
289	        }, 200);
290	    } catch {
291	        return c.json({ resolved: false }, 200);
292	    }
293	}
